    <span class="kw">await</span> <span class="fn">delay</span>(<span class="num">10</span>);  <span class="cm">// gap — bug window ──┘</span>
    <span class="cm">// ❌ WRITE overwrites concurrent update</span>
    sharedProgress = next;
  }
}</div>
