            <p>Give each task its own isolated progress slot. Compute the aggregate
            total by <strong>deriving it</strong> from all slots rather than
            accumulating into shared state:</p>
            <div class="code-block"><span class="cm">// FIXED — isolated per-task state</span>
<span class="kw">const</span> taskProgress = {};

<span class="kw">async function</span> <span class="fn">fixedTask</span>(id, steps) {
  taskProgress[id] = <span class="num">0</span>;
  <span class="kw">for</span> (<span class="kw">let</span> i = <span class="num">0</span>; i &lt; steps; i++) {
    <span class="kw">await</span> <span class="fn">delay</span>(<span class="fn">random</span>(<span class="num">80</span>,<span class="num">300</span>));
    <span class="cm">// ✅ Write ONLY to own slot</span>
    taskProgress[id] = ((i+<span class="num">1</span>) / steps) * <span class="num">100</span>;
    <span class="cm">// ✅ Total is DERIVED, never mutated</span>
    <span class="kw">const</span> total = <span class="fn">computeTotal</span>(taskProgress);
    <span class="fn">updateUI</span>(total);
  }
}

<span class="kw">function</span> <span class="fn">computeTotal</span>(slots) {
  <span class="cm">// Sum all task contributions proportionally</span>
  <span class="kw">const</span> vals = Object.<span class="fn">values</span>(slots);
  <span class="kw">return</span> vals.<span class="fn">reduce</span>((a,b) => a+b, <span class="num">0</span>) / vals.length;
}</div>
            <ul>
                <li>Each task only ever writes to <code>taskProgress[ownId]</code></li>
                <li>No two tasks share a write target — <strong>zero contention</strong></li>
                <li>The total is a pure <strong>derivation</strong>, always consistent</li>
                <li>Result is always clamped naturally to <strong>0–100%</strong></li>
            </ul>
