    box.scrollTop = box.scrollHeight;
}

function setStatus(id, text, cls) {
    const el = document.getElementById(id);
    el.textContent = text;
    el.className = `status-pill ${cls}`;
}

// ─────────────────────────────────────────────
//  Build task grid items
// ─────────────────────────────────────────────
const TASK_DEFS = [
    { name: '📦 Loader',    steps: 6 },
    { name: '🗄️ Database',  steps: 5 },
    { name: '🌐 Network',   steps: 7 },
    { name: '🖼️ Renderer',  steps: 4 },
];

function buildTaskGrid(gridId, prefix) {
    const grid = document.getElementById(gridId);
    grid.innerHTML = '';
    TASK_DEFS.forEach((t, i) => {
        const div = document.createElement('div');
        div.className = 'task-item';
        div.id = `${prefix}-task-${i}`;
        div.innerHTML = `
            <div class="task-name">${t.name}</div>
            <div class="task-bar-wrap">
                <div class="task-bar" id="${prefix}-tbar-${i}" style="width:0%"></div>
            </div>
            <div class="task-pct" id="${prefix}-tpct-${i}">0%</div>`;
        grid.appendChild(div);
    });
}

function updateTaskBar(prefix, i, pct) {
    const bar = document.getElementById(`${prefix}-tbar-${i}`);
    const lbl = document.getElementById(`${prefix}-tpct-${i}`);
    if (bar) bar.style.width = clamp(pct, 0, 100) + '%';
    if (lbl) lbl.textContent = Math.round(pct) + '%';
}

// ─────────────────────────────────────────────
//  BUGGY VERSION
// ─────────────────────────────────────────────
let sharedProgress = 0;       // ← the single shared (broken) accumulator
let buggyRunning   = false;

async function runBuggy() {
    if (buggyRunning) return;
    buggyRunning = true;

    // Reset
    sharedProgress = 0;
    buildTaskGrid('buggy-task-grid', 'buggy');
    document.getElementById('buggy-log').innerHTML = '';
    updateBuggyUI(0);
    document.getElementById('buggy-btn').disabled = true;
    setStatus('buggy-status', '⚙ RUNNING', 'status-running');
    addLog('buggy-log', 'Starting 4 concurrent buggy tasks…', 'warn');

    const totalSteps = TASK_DEFS.reduce((a, t) => a + t.steps, 0); // 22

    // Each task does a classic read-modify-write on sharedProgress
    async function buggyTask(id, taskDef) {
        const { name, steps } = taskDef;
        const increment = 100 / totalSteps; // each step should add ~4.5%

        for (let i = 0; i < steps; i++) {
            // Simulate async work
            await delay(rand(60, 280));

            // ─── BUG: Read-Modify-Write with artificial gap ───
            const readValue = sharedProgress;           // READ  (stale!)
            await delay(rand(5, 25));                   // GAP   (other tasks run here!)
            const newValue  = readValue + increment;    // MODIFY (based on stale read)
            sharedProgress  = newValue;                 // WRITE  (overwrites concurrent writes!)
            // ─────────────────────────────────────────────────

            const taskPct = ((i + 1) / steps) * 100;
            updateTaskBar('buggy', id, taskPct);

            const isOverflow = sharedProgress > 100.5;
            updateBuggyUI(sharedProgress);

            if (isOverflow) {
                addLog('buggy-log',
                    `⚠ OVERFLOW! ${name} step ${i+1}: shared=${sharedProgress.toFixed(1)}% (expected ≤100%)`,
                    'error');
            } else {
                addLog('buggy-log',
                    `${name} step ${i+1}/${steps} → shared=${sharedProgress.toFixed(1)}%`,
                    'normal');
            }
        }
        addLog('buggy-log', `${name} done. Final shared=${sharedProgress.toFixed(1)}%`, 'warn');
    }

    // Launch all tasks concurrently — no coordination
    await Promise.all(TASK_DEFS.map((t, i) => buggyTask(i, t)));

    const finalVal = sharedProgress;
    updateBuggyUI(finalVal);

    if (finalVal > 100.5) {
        addLog('buggy-log',
            `✗ FINAL = ${finalVal.toFixed(1)}% — CORRUPTED (exceeded 100%)`, 'error');
        setStatus('buggy-status', `✗ CORRUPTED: ${finalVal.toFixed(1)}%`, 'status-done-err');
    } else if (finalVal < 99) {
        addLog('buggy-log',
            `✗ FINAL = ${finalVal.toFixed(1)}% — CORRUPTED (lost updates)`, 'error');
        setStatus('buggy-status', `✗ CORRUPTED: ${finalVal.toFixed(1)}%`, 'status-done-err');
    } else {
        addLog('buggy-log',
            `FINAL = ${finalVal.toFixed(1)}% — happened to be OK this run (run again!)`, 'info');
        setStatus('buggy-status', `~ OK this run: ${finalVal.toFixed(1)}%`, 'status-running');
    }

    buggyRunning = false;
    document.getElementById('buggy-btn').disabled = false;
}

function updateBuggyUI(val) {
    const pct    = val;
    const capped = clamp(pct, 0, 200); // allow overflow to be visible
    const barPct = clamp(pct, 0, 100);
    const isOver = pct > 100.5;

    const bar   = document.getElementById('buggy-bar');
    const label = document.getElementById('buggy-pct-label');
    const total = document.getElementById('buggy-total');

    bar.style.width = barPct + '%';
    if (isOver) {
        bar.classList.add('overflow');
    } else {
        bar.classList.remove('overflow');
    }

    const display = Math.round(pct) + '%';
    label.textContent = display;
    total.textContent = display;

    if (isOver) {
        total.classList.add('overflow-val');
        label.style.color = '#ff4444';
    } else {
        total.classList.remove('overflow-val');
        label.style.color = '';
    }
}

// ─────────────────────────────────────────────
//  FIXED VERSION
// ─────────────────────────────────────────────
let taskProgress = {};   // isolated per-task slots
let fixedRunning  = false;

function computeFixedTotal() {
    const vals = Object.values(taskProgress);
    if (vals.length === 0) return 0;
    return vals.reduce((a, b) => a + b, 0) / vals.length;
}

async function runFixed() {
    if (fixedRunning) return;
    fixedRunning = true;

    // Reset
    taskProgress = {};
    buildTaskGrid('fixed-task-grid', 'fixed');
    document.getElementById('fixed-log').innerHTML = '';
    updateFixedUI(0);
    document.getElementById('fixed-btn').disabled = true;
    setStatus('fixed-status', '⚙ RUNNING', 'status-running');
    addLog('fixed-log', 'Starting 4 concurrent fixed tasks…', 'success');

    async function fixedTask(id, taskDef) {
        const { name, steps } = taskDef;
        taskProgress[id] = 0;   // own isolated slot

        for (let i = 0; i < steps; i++) {
            await delay(rand(60, 280));

            // ─── FIX: Write ONLY to own slot ───────────────────
            taskProgress[id] = ((i + 1) / steps) * 100;
            // ─── FIX: Derive total — never mutate shared state ──
            const total = computeFixedTotal();
            // ────────────────────────────────────────────────────

            updateTaskBar('fixed', id, taskProgress[id]);
            updateFixedUI(total);

            addLog('fixed-log',
                `${name} step ${i+1}/${steps} → own=${taskProgress[id].toFixed(0)}% total=${total.toFixed(1)}%`,
                'success');
        }
        addLog('fixed-log', `${name} done. Total=${computeFixedTotal().toFixed(1)}%`, 'info');
    }

    await Promise.all(TASK_DEFS.map((t, i) => fixedTask(i, t)));

    const finalTotal = computeFixedTotal();
    updateFixedUI(finalTotal);

    if (Math.abs(finalTotal - 100) < 1) {
        addLog('fixed-log', `✓ FINAL = ${finalTotal.toFixed(1)}% — CORRECT`, 'success');
        setStatus('fixed-status', `✓ CORRECT: ${finalTotal.toFixed(1)}%`, 'status-done-ok');
    } else {
        addLog('fixed-log', `? FINAL = ${finalTotal.toFixed(1)}%`, 'info');
        setStatus('fixed-status', `FINAL: ${finalTotal.toFixed(1)}%`, 'status-done-ok');
    }

    fixedRunning = false;
    document.getElementById('fixed-btn').disabled = false;
}

function updateFixedUI(val) {
    const pct   = clamp(val, 0, 100);
    const bar   = document.getElementById('fixed-bar');
    const label = document.getElementById('fixed-pct-label');
    const total = document.getElementById('fixed-total');

    bar.style.width       = pct + '%';
    label.textContent     = Math.round(pct) + '%';
    total.textContent     = Math.round(pct) + '%';
}

// ─────────────────────────────────────────────
//  Init
// ─────────────────────────────────────────────
buildTaskGrid('buggy-task-grid', 'buggy');
buildTaskGrid('fixed-task-grid', 'fixed');
</script>
