//  TASK GRID HELPERS
// ─────────────────────────────────────────────
function buildTaskGrid(containerId, prefix) {
    const container = document.getElementById(containerId);
    container.innerHTML = '';
    for (let i = 0; i < TASK_COUNT; i++) {
        const div = document.createElement('div');
        div.className = 'task-item';
        div.id = `${prefix}-task-${i}`;
        div.innerHTML = `
            <div class="task-name">Task ${i + 1}</div>
            <div class="task-contribution">+${CHUNK}%</div>
            <div class="task-status" id="${prefix}-task-status-${i}">idle</div>
        `;
        container.appendChild(div);
    }
}

function setTaskState(prefix, i, state, statusText) {
    const el = document.getElementById(`${prefix}-task-${i}`);
    const st = document.getElementById(`${prefix}-task-status-${i}`);
    if (el) el.className = `task-item ${state}`;
    if (st) st.textContent = statusText;
}

// ─────────────────────────────────────────────
//  PROGRESS BAR HELPERS
// ─────────────────────────────────────────────
function setProgress(prefix, pct, overflow = false) {
    const bar   = document.getElementById(`${prefix}-bar`);
    const label = document.getElementById(`${prefix}-pct`);
    const warn  = document.getElementById(`${prefix}-warning`);

    const displayPct = Math.min(pct, 100);
    bar.style.width = displayPct + '%';
    label.textContent = pct.toFixed(1) + '%';

    if (overflow || pct > 100) {
        bar.classList.add('overflow');
        warn.textContent = `⚠️ OVERFLOW! Progress is ${pct.toFixed(1)}% — exceeded 100%!`;
    } else {
        bar.classList.remove('overflow');
        if (prefix === 'fixed') {
            warn.textContent = pct >= 100 ? '✅ Exactly 100% — no lost updates!' : '';
        } else {
            warn.textContent = '';
        }
    }
}

function resetPanel(prefix) {
    setProgress(prefix, 0);
    document.getElementById(`${prefix}-warning`).textContent = '';
    document.getElementById(`${prefix}-actual`).textContent  = '—';
    document.getElementById(`${prefix}-lost`).textContent    = '—';
    document.getElementById(`${prefix}-bar`).classList.remove('overflow');

    const ri = document.getElementById(`${prefix}-race-indicator`);
    ri.className = 'race-indicator idle';
    ri.textContent = 'Waiting to start...';
}

// ─────────────────────────────────────────────
//  ██████╗ ██╗   ██╗ ██████╗  ██████╗ ██╗   ██╗
//  ██╔══██╗██║   ██║██╔════╝ ██╔════╝ ╚██╗ ██╔╝
//  ██████╔╝██║   ██║██║  ███╗██║  ███╗ ╚████╔╝
//  ██╔══██╗██║   ██║██║   ██║██║   ██║  ╚██╔╝
//  ██████╔╝╚██████╔╝╚██████╔╝╚██████╔╝   ██║
//  ╚═════╝  ╚═════╝  ╚═════╝  ╚═════╝    ╚═╝
//  BUGGY VERSION — shared mutable state, no synchronization
// ─────────────────────────────────────────────
let buggyRunning = false;

async function runBuggy() {
    if (buggyRunning) return;
    buggyRunning = true;

    const btn = document.getElementById('buggy-btn');
    btn.disabled = true;
    btn.textContent = '⏳ Running...';

    resetPanel('buggy');
    clearLog('buggy-log');
    buildTaskGrid('buggy-tasks', 'buggy');

    // ⚠️  THE BUG: a plain shared variable, no locking
    let sharedProgress = 0;
    let updateCount    = 0;
    let conflictCount  = 0;

    const ri = document.getElementById('buggy-race-indicator');
    ri.className = 'race-indicator active';
    ri.textContent = '⚡ Race condition in progress...';

    log('buggy-log', `Starting ${TASK_COUNT} concurrent tasks (each adds ${CHUNK}%)`, 'warn');
    log('buggy-log', 'Expected final value: 100% — watch what actually happens!', 'warn');

    // Launch all tasks simultaneously — THIS is the problem
    const tasks = Array.from({ length: TASK_COUNT }, (_, i) => {
        return new Promise(resolve => {
            setTimeout(async () => {
                setTaskState('buggy', i, 'running', 'reading...');

                // ── RACE CONDITION ZONE ──────────────────────────────────
                // Step 1: Read current value (may be stale!)
                const readValue = sharedProgress;

                // Simulate async work (another task may write here!)
                await new Promise(r => setTimeout(r, randDelay()));

                // Step 2: Compute new value based on the (now possibly stale) read
                const newValue = readValue + CHUNK;

                // Detect if someone else wrote between our read and write
                if (sharedProgress !== readValue) {
                    conflictCount++;
                    setTaskState('buggy', i, 'conflict', '💥 conflict!');
                    log('buggy-log',
                        `Task ${i+1}: READ ${readValue}% but state is now ${sharedProgress}% → LOST UPDATE! Writing ${newValue}% anyway`,
                        'error');
                } else {
                    setTaskState('buggy', i, 'running', 'writing...');
                }

                // Step 3: Write back — possibly overwriting another task's work!
                sharedProgress = newValue;
                updateCount++;

                setProgress('buggy', sharedProgress, sharedProgress > 100);
                document.getElementById('buggy-actual').textContent = sharedProgress.toFixed(1) + '%';

                if (sharedProgress !== readValue + CHUNK || conflictCount > 0) {
                    log('buggy-log',
                        `Task ${i+1}: Wrote ${newValue}% (read was ${readValue}%, current is ${sharedProgress}%)`,
                        sharedProgress > 100 ? 'error' : 'warn');
                } else {
                    log('buggy-log', `Task ${i+1}: OK — wrote ${newValue}%`, 'info');
                }

                setTaskState('buggy', i, 'done', '✓ done');
                resolve();
            }, randDelay());
        });
    });

    await Promise.all(tasks);

    // Final assessment
    const expected   = TASK_COUNT * CHUNK;
    const lostUpdates = Math.round((expected - sharedProgress) / CHUNK);

    document.getElementById('buggy-actual').textContent = sharedProgress.toFixed(1) + '%';
    document.getElementById('buggy-lost').textContent   =
        sharedProgress === expected ? '0' : `~${Math.abs(lostUpdates)}`;

    ri.textContent = `⚠️ Done! Final: ${sharedProgress}% | Conflicts detected: ${conflictCount}`;

    if (sharedProgress !== expected) {
        log('buggy-log', `─── FINAL: ${sharedProgress}% (expected ${expected}%) — ${conflictCount} conflicts! ───`, 'error');
        setProgress('buggy', sharedProgress, sharedProgress > 100);
    } else {
        log('buggy-log', `─── FINAL: ${sharedProgress}% — Got lucky this run! Try again. ───`, 'warn');
    }

    btn.disabled = false;
    btn.textContent = '🐛 Run Buggy Demo Again';
    buggyRunning = false;
}

// ─────────────────────────────────────────────
//  ███████╗██╗██╗  ██╗███████╗██████╗
//  ██╔════╝██║╚██╗██╔╝██╔════╝██╔══██╗
//  █████╗  ██║ ╚███╔╝ █████╗  ██║  ██║
//  ██╔══╝  ██║ ██╔██╗ ██╔══╝  ██║  ██║
//  ██║     ██║██╔╝ ██╗███████╗██████╔╝
//  ╚═╝     ╚═╝╚═╝  ╚═╝╚══════╝╚═════╝
//  FIXED VERSION — Promise-based mutex (serial queue)
// ─────────────────────────────────────────────
let fixedRunning = false;

// ✅ THE FIX: A simple async mutex using a chained Promise queue
class AsyncMutex {
    constructor() {
        this._queue = Promise.resolve();   // start with a resolved promise
    }

    // Acquire the lock: returns a release function
    acquire() {
        let release;
        // Chain onto the current queue tail
        const next = new Promise(resolve => { release = resolve; });
        // The caller must wait for the current tail to resolve
        const waitForLock = this._queue.then(() => release);
        // Advance the queue tail to the new promise
        this._queue = next;
        return waitForLock;
    }
}

async function runFixed() {
    if (fixedRunning) return;
    fixedRunning = true;

    const btn = document.getElementById('fixed-btn');
    btn.disabled = true;
    btn.textContent = '⏳ Running...';

    resetPanel('fixed');
    clearLog('fixed-log');
    buildTaskGrid('fixed-tasks', 'fixed');

    let sharedProgress = 0;
    const mutex = new AsyncMutex();

    const ri = document.getElementById('fixed-race-indicator');
    ri.className = 'race-indicator active';
    ri.textContent = '🔒 Mutex protecting shared state...';

    log('fixed-log', `Starting ${TASK_COUNT} concurrent tasks (each adds ${CHUNK}%)`, 'info');
    log('fixed-log', 'Mutex ensures serial access — no lost updates possible', 'success');

    const tasks = Array.from({ length: TASK_COUNT }, (_, i) => {
        return new Promise(resolve => {
            setTimeout(async () => {
                setTaskState('fixed', i, 'running', 'waiting...');
                log('fixed-log', `Task ${i+1}: Requesting mutex lock...`, 'normal');

                // ── CRITICAL SECTION (protected by mutex) ────────────────
                const release = await mutex.acquire();
                // At this point, we are the ONLY task in the critical section

                try {
                    setTaskState('fixed', i, 'running', '🔒 locked');
                    log('fixed-log', `Task ${i+1}: Lock acquired — reading ${sharedProgress}%`, 'info');

                    // Simulate async work while holding the lock
                    await new Promise(r => setTimeout(r, randDelay()));

                    // Safe read-modify-write: no other task can interfere
                    const before = sharedProgress;
                    sharedProgress += CHUNK;

                    setProgress('fixed', sharedProgress);
                    document.getElementById('fixed-actual').textContent = sharedProgress.toFixed(1) + '%';

                    log('fixed-log',
                        `Task ${i+1}: ${before}% → ${sharedProgress}% ✓ (lock held, no conflicts possible)`,
                        'success');

                    setTaskState('fixed', i, 'done', '✓ done');
                } finally {
                    // ALWAYS release the lock, even if an error occurred
                    release();
                    log('fixed-log', `Task ${i+1}: Lock released`, 'normal');
                }
                // ── END CRITICAL SECTION ─────────────────────────────────

                resolve();
            }, randDelay());
        });
    });

    await Promise.all(tasks);

    const expected = TASK_COUNT * CHUNK;
    document.getElementById('fixed-actual').textContent = sharedProgress.toFixed(1) + '%';
    document.getElementById('fixed-lost').textContent   = '0';

    ri.className = 'race-indicator idle';
    ri.textContent = `✅ Done! Final: ${sharedProgress}% — Exactly correct!`;

    setProgress('fixed', sharedProgress);

    log('fixed-log', `─── FINAL: ${sharedProgress}% (expected ${expected}%) — Perfect! ───`, 'success');

    btn.disabled = false;
    btn.textContent = '✅ Run Fixed Demo Again';
    fixedRunning = false;
}

// ─────────────────────────────────────────────
//  INIT
// ─────────────────────────────────────────────
buildTaskGrid('buggy-tasks', 'buggy');
buildTaskGrid('fixed-tasks', 'fixed');
</script>
</body>
</html>
