                skipped increments, wrong totals, and values that can exceed 100%.
            </p>
            <div class="code-block">
<span class="code-comment">// ❌ BUGGY — classic read-modify-write race</span>
<span class="code-keyword">let</span> <span class="code-var">progress</span> = <span class="code-num">0</span>;

<span class="code-keyword">async function</span> buggyTask(chunk) {
  <span class="code-keyword">await</span> simulateWork(); <span class="code-comment">// yields to event loop</span>
  <span class="code-keyword">const</span> <span class="code-var">old</span> = <span class="code-var">progress</span>; <span class="code-comment">// READ stale value</span>
  <span class="code-var">progress</span> = <span class="code-var">old</span> + chunk; <span class="code-comment">// WRITE — overwrites others!</span>
  <span class="code-bad">// Task A reads 20, Task B reads 20</span>
  <span class="code-bad">// Task A writes 35, Task B writes 40</span>
  <span class="code-bad">// Task A's update is LOST → only +20 not +35</span>
}
            </div>
        </div>
        <div class="exp-card fix-card">
            <h3>✅ The Fix: Serialized Update Queue</h3>
