                each task <strong>enqueues its update</strong>. A single dedicated
                processor drains the queue one-at-a-time, guaranteeing that every
                update is applied atomically and in order.
            </p>
            <p>
                This is the JavaScript equivalent of a <strong>mutex / lock</strong>
                — no two updates can interfere because only one runs at a time.
            </p>
            <div class="code-block">
<span class="code-comment">// ✅ FIXED — serialized update queue</span>
<span class="code-keyword">let</span> <span class="code-var">progress</span> = <span class="code-num">0</span>;
<span class="code-keyword">const</span> <span class="code-var">queue</span> = [];
<span class="code-keyword">let</span> <span class="code-var">processing</span> = <span class="code-num">false</span>;

<span class="code-keyword">function</span> enqueueUpdate(chunk) {
  <span class="code-var">queue</span>.push(chunk); <span class="code-comment">// safe: just append</span>
  processQueue();
}

<span class="code-keyword">async function</span> processQueue() {
  <span class="code-keyword">if</span> (<span class="code-var">processing</span>) <span class="code-keyword">return</span>; <span class="code-comment">// only one processor</span>
  <span class="code-var">processing</span> = <span class="code-num">true</span>;
  <span class="code-keyword">while</span> (<span class="code-var">queue</span>.length > <span class="code-num">0</span>) {
    <span class="code-var">progress</span> += <span class="code-var">queue</span>.shift(); <span class="code-good">// atomic apply</span>
  }
  <span class="code-var">processing</span> = <span class="code-num">false</span>;
}
