<script>
// ─────────────────────────────────────────────────────────────
//  SHARED UTILITIES
// ─────────────────────────────────────────────────────────────

const TASK_CONFIGS = [
    { name: 'Task A', chunk: 15, delay: 80  },
    { name: 'Task B', chunk: 20, delay: 60  },
    { name: 'Task C', chunk: 18, delay: 100 },
    { name: 'Task D', chunk: 12, delay: 55  },
    { name: 'Task E', chunk: 22, delay: 90  },
    { name: 'Task F', chunk: 13, delay: 70  },
];
// Total chunks = 100 ✓

function sleep(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

function now() {
    return performance.now().toFixed(1);
}

function addLog(logEl, message, cls = 'log-normal') {
    const entry = document.createElement('div');
    entry.className = `log-entry ${cls}`;
    entry.innerHTML = `<span class="log-time">[${now()}ms]</span> ${message}`;
    logEl.appendChild(entry);
    logEl.scrollTop = logEl.scrollHeight;
}

function buildTaskGrid(containerId, configs) {
    const container = document.getElementById(containerId);
    container.innerHTML = '';
    configs.forEach((cfg, i) => {
        const el = document.createElement('div');
        el.className = 'task-item';
        el.id = `${containerId}-task-${i}`;
        el.innerHTML = `
            <div class="task-name">${cfg.name}</div>
            <div class="task-progress" id="${containerId}-tp-${i}">+${cfg.chunk}%</div>
            <div class="task-status" id="${containerId}-ts-${i}">waiting</div>
        `;
        container.appendChild(el);
    });
}

function setTaskState(containerId, i, state, extraText = '') {
    const el    = document.getElementById(`${containerId}-task-${i}`);
    const tsEl  = document.getElementById(`${containerId}-ts-${i}`);
    if (!el || !tsEl) return;
    el.className = 'task-item ' + state;
    const labels = { running: '⚙️ running', done: '✅ done', 'done-buggy': '⚠️ wrote', waiting: '⏳ waiting' };
    tsEl.textContent = (labels[state] || state) + (extraText ? ' ' + extraText : '');
}

// ─────────────────────────────────────────────────────────────
//  STATS
// ─────────────────────────────────────────────────────────────

let raceCount  = 0;
let skipCount  = 0;

function updateStats() {
    document.getElementById('race-count').textContent = raceCount;
    document.getElementById('skip-count').textContent = skipCount;
}

// ─────────────────────────────────────────────────────────────
//  BUGGY IMPLEMENTATION
// ─────────────────────────────────────────────────────────────

let buggyProgress = 0;

function updateBuggyBar(value) {
    const pct   = Math.min(value, 150); // allow visual overflow up to 150
    const bar   = document.getElementById('buggy-bar');
    const label = document.getElementById('buggy-pct');
    const warn  = document.getElementById('buggy-overflow-label');

    bar.style.width = Math.min(pct, 100) + '%';

    if (value > 100) {
        bar.classList.add('overflow');
        warn.textContent = `🔥 ${value}%!`;
        label.style.color = '#ff4444';
    } else {
        bar.classList.remove('overflow');
        warn.textContent = '';
        label.style.color = '#fff';
    }
    label.textContent = value + '%';
}

async function runBuggy() {
    const btn    = document.getElementById('btn-buggy');
    const logEl  = document.getElementById('buggy-log');
    btn.disabled = true;
    logEl.innerHTML = '';
    buggyProgress = 0;
    raceCount     = 0;
    skipCount     = 0;
    updateBuggyBar(0);
    buildTaskGrid('buggy-tasks', TASK_CONFIGS);
    updateStats();

    addLog(logEl, '🚀 Starting 6 concurrent buggy tasks...', 'log-warn');
    addLog(logEl, `📊 Expected final: 100% | Actual will differ`, 'log-info');

    // Track what each task read vs wrote to detect races
    const snapshots = [];

    const tasks = TASK_CONFIGS.map((cfg, i) => {
        return (async () => {
            setTaskState('buggy-tasks', i, 'running');
            addLog(logEl,
                `<span class="log-task">${cfg.name}</span> started (will add +${cfg.chunk}%)`,
                'log-normal');

            // Simulate async work — this yields to the event loop
            // allowing other tasks to also read the shared variable
            await sleep(cfg.delay + Math.random() * 30);

            // ❌ BUGGY: Read-Modify-Write — NOT atomic
            const readValue = buggyProgress;   // READ  (stale!)
            await sleep(2);                    // tiny yield — makes race more visible
            const writeValue = readValue + cfg.chunk; // MODIFY
            buggyProgress = writeValue;        // WRITE (may overwrite another task's write)

            snapshots.push({ task: cfg.name, read: readValue, wrote: writeValue, chunk: cfg.chunk });

            setTaskState('buggy-tasks', i, 'done-buggy', `→${writeValue}%`);
            addLog(logEl,
                `<span class="log-task">${cfg.name}</span> read=<span class="log-warn">${readValue}%</span> wrote=<span class="log-error">${writeValue}%</span>`,
                'log-warn');

            updateBuggyBar(buggyProgress);
        })();
    });

    await Promise.all(tasks);

    // Analyze races
    // A race occurs when two tasks read the same value (or a stale one)
    const sortedSnaps = [...snapshots].sort((a, b) => a.read - b.read);
    for (let i = 0; i < sortedSnaps.length - 1; i++) {
        if (sortedSnaps[i].read === sortedSnaps[i+1].read) {
            raceCount++;
        }
    }

    // Skipped updates: difference between expected (100) and actual
    const expectedFinal = TASK_CONFIGS.reduce((s, c) => s + c.chunk, 0);
    const actualFinal   = buggyProgress;
    skipCount = Math.abs(expectedFinal - actualFinal);

    updateStats();
    document.getElementById('buggy-final-value').textContent = actualFinal + '%';

    const isCorrect = actualFinal === 100;
    addLog(logEl,
        `🏁 Final: <strong>${actualFinal}%</strong> (expected 100%) ${isCorrect ? '— got lucky!' : '— CORRUPTED ❌'}`,
        isCorrect ? 'log-success' : 'log-error');

    if (actualFinal > 100) {
        addLog(logEl, `🔥 Progress EXCEEDED 100% by ${actualFinal - 100}%!`, 'log-error');
    } else if (actualFinal < 100) {
        addLog(logEl, `⚠️ Lost ${100 - actualFinal}% of progress due to race!`, 'log-error');
    }

    btn.disabled = false;
}

// ─────────────────────────────────────────────────────────────
//  FIXED IMPLEMENTATION — Serialized Update Queue
// ─────────────────────────────────────────────────────────────

let fixedProgress   = 0;
let updateQueue     = [];
let queueProcessing = false;

function enqueueProgressUpdate(chunk, taskName, logEl) {
    updateQueue.push({ chunk, taskName });
    addLog(logEl,
        `<span class="log-task">${taskName}</span> 📥 enqueued +${chunk}% (queue size: ${updateQueue.length})`,
        'log-info');
    drainQueue(logEl);
}

async function drainQueue(logEl) {
    // Guard: only one drainer runs at a time
    if (queueProcessing) return;
    queueProcessing = true;

    while (updateQueue.length > 0) {
        const { chunk, taskName } = updateQueue.shift();
        const before = fixedProgress;
        fixedProgress += chunk;   // ✅ Atomic: only one writer ever runs here
        const after  = fixedProgress;

        addLog(logEl,
            `<span class="log-task">${taskName}</span> ✅ applied: ${before}% + ${chunk}% = <span style="color:#44ff88">${after}%</span>`,
            'log-success');

        updateFixedBar(fixedProgress);

        // Tiny yield so we can see each update visually
        await sleep(30);
    }

    queueProcessing = false;
}

function updateFixedBar(value) {
    const bar   = document.getElementById('fixed-bar');
    const label = document.getElementById('fixed-pct');
    bar.style.width = Math.min(value, 100) + '%';
    label.textContent = value + '%';
}

async function runFixed() {
    const btn    = document.getElementById('btn-fixed');
    const logEl  = document.getElementById('fixed-log');
    btn.disabled = true;
    logEl.innerHTML = '';
    fixedProgress   = 0;
    updateQueue     = [];
    queueProcessing = false;
    updateFixedBar(0);
    buildTaskGrid('fixed-tasks', TASK_CONFIGS);

    addLog(logEl, '🚀 Starting 6 concurrent FIXED tasks...', 'log-success');
    addLog(logEl, '📦 Updates are serialized via queue — no races possible', 'log-info');

    const tasks = TASK_CONFIGS.map((cfg, i) => {
        return (async () => {
            setTaskState('fixed-tasks', i, 'running');
            addLog(logEl,
                `<span class="log-task">${cfg.name}</span> started (will add +${cfg.chunk}%)`,
                'log-normal');

            // Same async work as the buggy version
            await sleep(cfg.delay + Math.random() * 30);

            // ✅ FIXED: Don't write directly — enqueue the update
            enqueueProgressUpdate(cfg.chunk, cfg.name, logEl);
            setTaskState('fixed-tasks', i, 'done');
        })();
    });

    await Promise.all(tasks);

    // Wait for queue to fully drain
    while (queueProcessing || updateQueue.length > 0) {
        await sleep(50);
    }

    const finalVal = fixedProgress;
    document.getElementById('fixed-final-value').textContent = finalVal + '%';

    addLog(logEl,
        `🏁 Final: <strong>${finalVal}%</strong> (expected 100%) ${finalVal === 100 ? '— CORRECT ✅' : '— ERROR'}`,
        finalVal === 100 ? 'log-success' : 'log-error');

    btn.disabled = false;
}

// ─────────────────────────────────────────────────────────────
//  INIT
// ─────────────────────────────────────────────────────────────

buildTaskGrid('buggy-tasks', TASK_CONFIGS);
buildTaskGrid('fixed-tasks', TASK_CONFIGS);
</script>
</body>
</html>
```

---

## What this demo does

### 🐛 Buggy Side
- **6 tasks run concurrently** via `Promise.all` + `setTimeout`
- Each task does a **read → tiny yield → write** sequence
- The `await sleep(2)` between read and write is the key — it lets other tasks **read the same stale value** before anyone writes back
- Results: skipped updates, lost increments, totals that can be **under or over 100%**, glitch animation on overflow

### ✅ Fixed Side
- Tasks still run concurrently and do the same async work
- Instead of writing directly, each task **enqueues its chunk**
- A single `drainQueue()` processor applies updates **one at a time** with a `processing` guard flag
- This is JavaScript's equivalent of a **mutex** — the final value is **always exactly 100%**

### 📊 Stats tracked
| Stat | Meaning |
|------|---------|
| Buggy Final % | What the corrupted shared variable ends up at |
| Fixed Final % | Always 100% |
| Race Conditions | How many tasks read the same stale value |
| Skipped Updates | How many percentage points were lost or gained |

