<script>
// ─────────────────────────────────────────────────────────────────────────────
// SHARED CONFIG
// ─────────────────────────────────────────────────────────────────────────────
const TASKS = [
  { name: 'Fetch user data',      weight: 20, steps: 4,  baseDelay: 120 },
  { name: 'Load asset bundle',    weight: 25, steps: 5,  baseDelay: 90  },
  { name: 'Parse configuration',  weight: 15, steps: 3,  baseDelay: 150 },
  { name: 'Initialize database',  weight: 30, steps: 6,  baseDelay: 80  },
  { name: 'Warm up cache',        weight: 10, steps: 2,  baseDelay: 200 },
];

// ─────────────────────────────────────────────────────────────────────────────
// UTILITIES
// ─────────────────────────────────────────────────────────────────────────────
function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

function jitter(base) {
  // Add random jitter to make race conditions more visible
  return base + Math.floor(Math.random() * base * 0.8);
}

function appendLog(logId, message, type = '') {
  const box = document.getElementById(logId);
  const entry = document.createElement('div');
  entry.className = 'log-entry' + (type ? ` ${type}` : '');
  const ts = new Date().toLocaleTimeString('en-US', { hour12: false,
    hour: '2-digit', minute: '2-digit', second: '2-digit',
    fractionalSecondDigits: 2 });
  entry.textContent = `[${ts}] ${message}`;
  box.appendChild(entry);
  box.scrollTop = box.scrollHeight;
}

function buildTaskUI(containerId, tasks) {
  const container = document.getElementById(containerId);
  container.innerHTML = '';
  tasks.forEach((t, i) => {
    const el = document.createElement('div');
    el.className = 'task-item';
    el.id = `${containerId}-task-${i}`;
    el.innerHTML = `
      <div class="task-dot"></div>
      <span class="task-name">${t.name}</span>
      <span class="task-contribution" id="${containerId}-contrib-${i}">+${t.weight}%</span>
    `;
    container.appendChild(el);
  });
}

function setTaskState(containerId, idx, state, contrib) {
  const el = document.getElementById(`${containerId}-task-${idx}`);
  if (!el) return;
  el.className = `task-item ${state}`;
  if (contrib !== undefined) {
    document.getElementById(`${containerId}-contrib-${idx}`).textContent = contrib;
  }
}

function updateBar(barId, pctId, warningId, value, updateCountId) {
  const clamped = Math.min(value, 110); // allow slight overflow to show bug
  const bar = document.getElementById(barId);
  const pct = document.getElementById(pctId);
  const warn = document.getElementById(warningId);
  const cnt = document.getElementById(updateCountId);

  bar.style.width = Math.min(clamped, 100) + '%';
  pct.textContent = Math.round(value) + '%';

  // Update counter
  const current = parseInt(cnt.textContent) || 0;
  cnt.textContent = current + 1;

  if (value > 100) {
    warn.textContent = `⚠ OVERFLOW! Progress exceeded 100% (got ${Math.round(value)}%) — race condition!`;
  } else if (value < 0) {
    warn.textContent = `⚠ UNDERFLOW! Negative progress — data lost!`;
  } else {
    warn.textContent = '';
  }
}

function resetUI(prefix) {
  document.getElementById(`${prefix}-bar`).style.width = '0%';
  document.getElementById(`${prefix}-pct`).textContent = '0%';
  document.getElementById(`${prefix}-warning`).textContent = '';
  document.getElementById(`${prefix}-log`).innerHTML = '';
  document.getElementById(`${prefix}-update-count`).textContent = '0';
  document.getElementById(`${prefix}-result`).textContent = 'Running…';
}

// ─────────────────────────────────────────────────────────────────────────────
// BUGGY IMPLEMENTATION
// Each task reads the global sharedProgress, adds its chunk, writes back.
// Race condition: tasks read stale values before others finish writing.
// ─────────────────────────────────────────────────────────────────────────────
let buggyRunning = false;

async function runBuggy() {
  if (buggyRunning) return;
  buggyRunning = true;

  const btn = document.getElementById('buggy-btn');
  btn.disabled = true;

  resetUI('buggy');
  buildTaskUI('buggy-tasks', TASKS);
  appendLog('buggy-log', 'Starting 5 concurrent tasks…', 'info');

  // ★ THE BUG: single shared mutable variable
  let sharedProgress = 0;
  let skipsDetected = 0;
  let overflowDetected = false;
  let lastSeen = 0;

  const runTask = async (task, idx) => {
    setTaskState('buggy-tasks', idx, 'running');
    appendLog('buggy-log', `Task "${task.name}" started`, 'info');

    const chunkSize = task.weight / task.steps;

    for (let step = 0; step < task.steps; step++) {
      await sleep(jitter(task.baseDelay));

      // ★ READ-MODIFY-WRITE on shared variable — classic race condition
      // Between the read and the write, other tasks may have already
      // modified sharedProgress, causing us to overwrite their changes.
      const readSnapshot = sharedProgress;           // READ stale value
      await sleep(jitter(20));                       // simulate async work gap
      sharedProgress = readSnapshot + chunkSize;     // WRITE back (may clobber!)

      const rounded = Math.round(sharedProgress);

      // Detect skips
      if (rounded - lastSeen > 15 && lastSeen > 0) {
        skipsDetected++;
        appendLog('buggy-log',
          `⚠ SKIP detected! ${lastSeen}% → ${rounded}% (jumped ${rounded - lastSeen}%)`, 'warn');
      }
      if (sharedProgress > 100 && !overflowDetected) {
        overflowDetected = true;
        appendLog('buggy-log',
          `⚠ OVERFLOW! sharedProgress = ${sharedProgress.toFixed(1)}%`, 'warn');
      }
      lastSeen = rounded;

      updateBar('buggy-bar', 'buggy-pct', 'buggy-warning', sharedProgress, 'buggy-update-count');
      appendLog('buggy-log',
        `Task[${idx}] step ${step+1}/${task.steps}: wrote ${sharedProgress.toFixed(1)}% (read was ${readSnapshot.toFixed(1)}%)`);
    }

    setTaskState('buggy-tasks', idx, 'done',
      sharedProgress > 100 ? `+${task.weight}% ⚠` : `+${task.weight}%`);
    appendLog('buggy-log', `Task "${task.name}" done`, 'ok');
  };

  // Launch ALL tasks concurrently — no coordination
  await Promise.all(TASKS.map((t, i) => runTask(t, i)));

  const final = Math.round(sharedProgress);
  const expected = TASKS.reduce((s, t) => s + t.weight, 0);
  const lost = expected - final;

  let resultMsg = '';
  if (final === expected) {
    resultMsg = `✅ Got lucky this run: ${final}% (expected ${expected}%)`;
  } else if (final > expected) {
    resultMsg = `🐛 OVERFLOW: Final = ${final}% (expected ${expected}%, excess = ${final - expected}%)`;
  } else {
    resultMsg = `🐛 DATA LOST: Final = ${final}% (expected ${expected}%, lost = ${lost}%)`;
  }

  document.getElementById('buggy-result').textContent = resultMsg;
  appendLog('buggy-log',
    `FINAL: ${final}% | Expected: ${expected}% | Skips: ${skipsDetected}`,
    final === expected ? 'ok' : 'warn');

  btn.disabled = false;
  buggyRunning = false;
}

// ─────────────────────────────────────────────────────────────────────────────
// FIXED IMPLEMENTATION
// Each task updates only its own slot. Total is derived by summing all slots.
// No task can interfere with another's data.
// ─────────────────────────────────────────────────────────────────────────────
let fixedRunning = false;

async function runFixed() {
  if (fixedRunning) return;
  fixedRunning = true;

  const btn = document.getElementById('fixed-btn');
  btn.disabled = true;

  resetUI('fixed');
  buildTaskUI('fixed-tasks', TASKS);
  appendLog('fixed-log', 'Starting 5 concurrent tasks (synchronized)…', 'info');

  // ★ THE FIX: each task owns its own progress slot
  const taskProgress = new Array(TASKS.length).fill(0);

  // Pure function — no shared mutable state, always consistent
  const getTotal = () => taskProgress.reduce((sum, v) => sum + v, 0);

  const runTask = async (task, idx) => {
    setTaskState('fixed-tasks', idx, 'running');
    appendLog('fixed-log', `Task "${task.name}" started`, 'info');

    const chunkSize = task.weight / task.steps;

    for (let step = 0; step < task.steps; step++) {
      await sleep(jitter(task.baseDelay));

      // ★ Each task ONLY writes to its own dedicated slot
      // No other task touches taskProgress[idx], so there is no conflict
      taskProgress[idx] += chunkSize;

      // Total is always recomputed from ground truth — never stale
      const total = getTotal();

      updateBar('fixed-bar', 'fixed-pct', 'fixed-warning', total, 'fixed-update-count');
      appendLog('fixed-log',
        `Task[${idx}] step ${step+1}/${task.steps}: slot[${idx}]=${taskProgress[idx].toFixed(1)}% total=${total.toFixed(1)}%`);
    }

    setTaskState('fixed-tasks', idx, 'done', `+${task.weight}% ✓`);
    appendLog('fixed-log', `Task "${task.name}" done`, 'ok');
  };

  // Same concurrent launch — but now safe
  await Promise.all(TASKS.map((t, i) => runTask(t, i)));

  const final = Math.round(getTotal());
  const expected = TASKS.reduce((s, t) => s + t.weight, 0);

  const resultMsg = final === expected
    ? `✅ Perfect: Final = ${final}% (exactly as expected)`
    : `⚠ Unexpected: Final = ${final}% (expected ${expected}%)`;

  document.getElementById('fixed-result').textContent = resultMsg;
  appendLog('fixed-log',
    `FINAL: ${final}% | Expected: ${expected}% | Slots: [${taskProgress.map(v => Math.round(v)).join(', ')}]`,
    'ok');

  btn.disabled = false;
  fixedRunning = false;
}
</script>
</body>
