<script>
// ─────────────────────────────────────────────
//  Utilities
// ─────────────────────────────────────────────
const delay = ms => new Promise(r => setTimeout(r, ms));
const rand  = (min, max) => Math.floor(Math.random() * (max - min + 1)) + min;

function appendLog(boxId, msg, cls = '') {
  const box = document.getElementById(boxId);
  const el  = document.createElement('div');
  el.className = 'log-entry ' + cls;
  el.textContent = `[${new Date().toLocaleTimeString('en',{hour12:false,hour:'2-digit',minute:'2-digit',second:'2-digit'})}] ${msg}`;
  box.appendChild(el);
  box.scrollTop = box.scrollHeight;
}

function clearLog(boxId) {
  document.getElementById(boxId).innerHTML = '';
}

function setTaskUI(listId, name, state) {
  const list = document.getElementById(listId);
  let item = document.getElementById(`${listId}-${name}`);
  if (!item) {
    item = document.createElement('div');
    item.className = 'task-item';
    item.id = `${listId}-${name}`;
    item.innerHTML = `<span class="task-name">${name}</span><span class="task-status"></span>`;
    list.appendChild(item);
  }
  item.className = `task-item ${state}`;
  const labels = { running: '⚙ Running…', done: '✔ Done', error: '✘ Error' };
  item.querySelector('.task-status').textContent = labels[state] || state;
}

function clearTaskList(listId) {
  document.getElementById(listId).innerHTML = '';
}

// ─────────────────────────────────────────────
//  BUGGY Implementation
// ─────────────────────────────────────────────
let buggyRunning  = false;
let sharedProgress = 0;   // ← THE BUG: shared mutable state
let buggyAnomalies = 0;

const BUGGY_TASKS = [
  { name: 'Task Alpha',   steps: 5  },
  { name: 'Task Beta',    steps: 4  },
  { name: 'Task Gamma',   steps: 6  },
  { name: 'Task Delta',   steps: 3  },
];

function updateBuggyBar(value, taskName) {
  const pct     = Math.round(value);
  const clamped = Math.min(pct, 150); // allow visual overflow for demo

  const bar    = document.getElementById('buggy-bar');
  const label  = document.getElementById('buggy-pct-label');
  const big    = document.getElementById('buggy-pct-big');
  const status = document.getElementById('buggy-status');

  const overflow = pct > 100;
  const displayW = Math.min(clamped, 100);

  bar.style.width = displayW + '%';
  label.textContent = pct + '%';
  big.textContent   = pct + '%';

  if (overflow) {
    bar.classList.add('overflow');
    big.classList.add('overflow-color');
    status.textContent = `⚠ OVERFLOW! ${pct}% — shared state corrupted by ${taskName}`;
    buggyAnomalies++;
    document.getElementById('buggy-anomaly-count').textContent = buggyAnomalies;
    appendLog('buggy-log', `OVERFLOW: ${pct}% written by ${taskName}`, 'err');
  } else {
    bar.classList.remove('overflow');
    big.classList.remove('overflow-color');
    status.textContent = `${taskName} updated → ${pct}%`;
  }
}

async function buggyTask(taskDef) {
  const { name, steps } = taskDef;
  setTaskUI('buggy-task-list', name, 'running');
  appendLog('buggy-log', `${name} started (${steps} steps)`, 'info');

  const prevValues = [];

  for (let i = 0; i < steps; i++) {
    await delay(rand(80, 350)); // random interleaving

    // ─── THE RACE CONDITION ───────────────────────────────────────
    // We read sharedProgress, then add our chunk, then write back.
    // Between our read and write, another task may have ALSO read
    // the old value and will overwrite ours — or we overwrite theirs.
    const before = sharedProgress;
    const chunk  = rand(8, 18);           // each step adds a random chunk
    sharedProgress = before + chunk;      // ← RACE: non-atomic read-modify-write
    // ──────────────────────────────────────────────────────────────

    // Detect skip anomaly (another task wrote between our steps)
    if (prevValues.length > 0) {
      const lastSeen = prevValues[prevValues.length - 1];
      if (sharedProgress < lastSeen) {
        buggyAnomalies++;
        document.getElementById('buggy-anomaly-count').textContent = buggyAnomalies;
        appendLog('buggy-log', `REGRESSION: ${name} sees ${Math.round(sharedProgress)}% (was ${Math.round(lastSeen)}%)`, 'warn');
      }
    }

    prevValues.push(sharedProgress);
    updateBuggyBar(sharedProgress, name);
    appendLog('buggy-log', `${name} step ${i+1}/${steps}: +${chunk} → total ${Math.round(sharedProgress)}%`, sharedProgress > 100 ? 'err' : 'warn');
  }

  setTaskUI('buggy-task-list', name, 'done');
  appendLog('buggy-log', `${name} finished`, 'ok');
}

async function runBuggy() {
  if (buggyRunning) return;
  buggyRunning    = true;
  sharedProgress  = 0;
  buggyAnomalies  = 0;

  document.getElementById('buggy-btn').disabled = true;
  document.getElementById('buggy-anomaly-count').textContent = '0';
  document.getElementById('buggy-bar').style.width = '0%';
  document.getElementById('buggy-bar').classList.remove('overflow');
  document.getElementById('buggy-pct-big').textContent = '0%';
  document.getElementById('buggy-pct-big').classList.remove('overflow-color');
  document.getElementById('buggy-pct-label').textContent = '0%';
  document.getElementById('buggy-status').textContent = 'Running…';
  clearLog('buggy-log');
  clearTaskList('buggy-task-list');

  appendLog('buggy-log', '⚡ All tasks launched simultaneously (shared state!)', 'warn');

  // Launch ALL tasks concurrently — they all share the same variable
  await Promise.all(BUGGY_TASKS.map(t => buggyTask(t)));

  const final = Math.round(sharedProgress);
  document.getElementById('buggy-status').textContent =
    `Done. Final value: ${final}% — Expected: 100% — Anomalies: ${buggyAnomalies}`;
  appendLog('buggy-log',
    `FINISHED: final=${final}% anomalies=${buggyAnomalies}`,
    final !== 100 ? 'err' : 'ok');

  buggyRunning = false;
  document.getElementById('buggy-btn').disabled = false;
}

// ─────────────────────────────────────────────
//  FIXED Implementation
// ─────────────────────────────────────────────
let fixedRunning = false;
let fixedOkCount = 0;

// Each task gets its own slot — no sharing
const FIXED_TASKS = [
  { name: 'Task Alpha', share: 25, steps: 5 },
  { name: 'Task Beta',  share: 25, steps: 4 },
  { name: 'Task Gamma', share: 30, steps: 6 },
  { name: 'Task Delta', share: 20, steps: 3 },
]; // shares sum to exactly 100

let taskSlices = {};  // isolated per-task progress

function totalProgress() {
  // Atomic read: sum all slices in one expression — no interleaving possible
  return Object.values(taskSlices).reduce((acc, v) => acc + v, 0);
}

function updateFixedBar(taskName) {
  const total = totalProgress();
  const pct   = Math.round(Math.min(total, 100)); // guaranteed ≤ 100

  document.getElementById('fixed-bar').style.width  = pct + '%';
  document.getElementById('fixed-pct-label').textContent = pct + '%';
  document.getElementById('fixed-pct-big').textContent   = pct + '%';
  document.getElementById('fixed-status').textContent    = `${taskName} updated → ${pct}%`;
}

async function fixedTask(taskDef) {
  const { name, share, steps } = taskDef;
  taskSlices[name] = 0;  // private slot, initialised to 0

  setTaskUI('fixed-task-list', name, 'running');
  appendLog('fixed-log', `${name} started (owns ${share}% in ${steps} steps)`, 'info');

  const chunkSize = share / steps;  // each step contributes an equal portion

  for (let i = 0; i < steps; i++) {
    await delay(rand(80, 350));

    // ─── THE FIX ─────────────────────────────────────────────────
    // Only write to OUR OWN slot. No other task touches taskSlices[name].
    // Reading the total is a pure function — no mutation, no race.
    taskSlices[name] += chunkSize;   // ← isolated write, zero contention
    // ──────────────────────────────────────────────────────────────

    const myProgress = Math.round(taskSlices[name]);
    updateFixedBar(name);
    appendLog('fixed-log',
      `${name} step ${i+1}/${steps}: my slice=${myProgress.toFixed(1)}% total=${Math.round(totalProgress())}%`,
      'ok');
  }

  setTaskUI('fixed-task-list', name, 'done');
  appendLog('fixed-log', `${name} finished (slice=${share}%)`, 'ok');
}

async function runFixed() {
  if (fixedRunning) return;
  fixedRunning = true;
  taskSlices   = {};

  document.getElementById('fixed-btn').disabled = true;
  document.getElementById('fixed-bar').style.width = '0%';
  document.getElementById('fixed-pct-big').textContent = '0%';
  document.getElementById('fixed-pct-label').textContent = '0%';
  document.getElementById('fixed-status').textContent = 'Running…';
  clearLog('fixed-log');
  clearTaskList('fixed-task-list');

  appendLog('fixed-log', '✅ All tasks launched — each owns a private slice', 'ok');

  await Promise.all(FIXED_TASKS.map(t => fixedTask(t)));

  const final = Math.round(totalProgress());
  const ok    = final === 100;

  if (ok) {
    fixedOkCount++;
    document.getElementById('fixed-ok-count').textContent = fixedOkCount;
  }

  document.getElementById('fixed-status').textContent =
    `Done. Final: ${final}% — ${ok ? '✅ Perfect!' : '⚠ Unexpected: ' + final + '%'}`;
  appendLog('fixed-log', `FINISHED: total=${final}% — ${ok ? 'CORRECT' : 'ERROR'}`, ok ? 'ok' : 'err');

  fixedRunning = false;
  document.getElementById('fixed-btn').disabled = false;
}
</script>
</body>
