<body>

<h1>⚡ Shared State Concurrency Bug</h1>
<p class="subtitle">Progress Bar Tracker — Race Condition Demonstration</p>

<div class="global-controls">
  <button class="btn-run-both" id="btnBoth">▶ Run Both Side-by-Side</button>
  <button class="btn-reset"    id="btnReset">↺ Reset All</button>
