</div>

<!-- EXPLANATION -->
<div class="explanation">
  <h2>📖 Why Does the Race Condition Happen?</h2>

  <div class="exp-grid">
    <div class="exp-block">
      <h3 class="red">❌ Buggy Code — Read-Modify-Write Without Lock</h3>
      <pre><span class="cm">// Shared mutable state — no protection</span>
<span class="kw">let</span> sharedProgress = <span class="num">0</span>;

<span class="kw">async function</span> <span class="fn">buggyTask</span>(name, contribution) {
  <span class="cm">// Simulate async work (fetch, I/O, etc.)</span>
  <span class="kw">await</span> <span class="fn">asyncWork</span>();

  <span class="cm">// ⚠️  READ  — captures stale value</span>
<span class="bug-line">  <span class="kw">const</span> current = sharedProgress;         </span>
  <span class="cm">// ⚠️  MODIFY — another task may have</span>
  <span class="cm">//             written between read & write</span>
<span class="bug-line">  <span class="kw">const</span> next = current + contribution;    </span>
  <span class="cm">// ⚠️  WRITE  — overwrites the other</span>
  <span class="cm">//             task's update silently!</span>
<span class="bug-line">  sharedProgress = next;                  </span>
}

<span class="cm">// Launch 5 tasks concurrently — all race!</span>
<span class="fn">Promise</span>.all(tasks.map(t => <span class="fn">buggyTask</span>(t)));</pre>
    </div>

    <div class="exp-block">
      <h3 class="green">✅ Fixed Code — Serialized Queue (Mutex)</h3>
      <pre><span class="cm">// Shared state + a serialization queue</span>
<span class="kw">let</span> sharedProgress = <span class="num">0</span>;
<span class="kw">let</span> queue = <span class="fn">Promise</span>.resolve(); <span class="cm">// mutex</span>

<span class="kw">function</span> <span class="fn">safeUpdate</span>(contribution) {
  <span class="cm">// Chain every update onto the queue.</span>
  <span class="cm">// Each update waits for the previous</span>
  <span class="cm">// one to finish before reading state.</span>
<span class="fix-line">  queue = queue.<span class="fn">then</span>(() => {              </span>
<span class="fix-line">    sharedProgress += contribution;        </span>
<span class="fix-line">  });                                      </span>
  <span class="kw">return</span> queue;
}

<span class="kw">async function</span> <span class="fn">fixedTask</span>(name, contribution) {
  <span class="kw">await</span> <span class="fn">asyncWork</span>();   <span class="cm">// work runs in parallel</span>
  <span class="kw">await</span> <span class="fn">safeUpdate</span>(contribution); <span class="cm">// update serialized</span>
}

<span class="fn">Promise</span>.all(tasks.map(t => <span class="fn">fixedTask</span>(t)));</pre>
    </div>
  </div>

  <!-- Timeline diagram -->
  <div class="race-diagram">
    <h3>⏱ Race Condition Timeline (Read-Modify-Write Conflict)</h3>
    <div class="timeline">
      <div class="tl-row">
        <span class="tl-label">Task A (+20%)</span>
        <div class="tl-bar">
          <div class="tl-seg tl-read"  style="flex:2">READ=0</div>
          <div class="tl-seg tl-wait"  style="flex:2">work…</div>
          <div class="tl-seg tl-write" style="flex:1">WRITE=20</div>
          <div class="tl-seg tl-wait"  style="flex:3">&nbsp;</div>
        </div>
      </div>
      <div class="tl-row">
        <span class="tl-label">Task B (+30%)</span>
        <div class="tl-bar">
          <div class="tl-seg tl-read"  style="flex:2">READ=0 ⚠</div>
          <div class="tl-seg tl-wait"  style="flex:3">work…</div>
          <div class="tl-seg tl-write" style="flex:1">WRITE=30</div>
          <div class="tl-seg tl-wait"  style="flex:2">&nbsp;</div>
        </div>
      </div>
      <div class="tl-row">
        <span class="tl-label">Task C (+25%)</span>
        <div class="tl-bar">
          <div class="tl-seg tl-wait"  style="flex:1">&nbsp;</div>
          <div class="tl-seg tl-read"  style="flex:2">READ=0 ⚠</div>
          <div class="tl-seg tl-wait"  style="flex:3">work…</div>
          <div class="tl-seg tl-write" style="flex:1">WRITE=25</div>
          <div class="tl-seg tl-wait"  style="flex:1">&nbsp;</div>
        </div>
      </div>
      <div class="conflict-arrow">
        ⚠ All tasks read stale value (0) → final result is 25% instead of expected 75%! Updates from A &amp; B are lost.
      </div>
    </div>
  </div>

  <div style="margin-top:16px; background:#0f1117; border-radius:10px; padding:16px; font-size:0.82rem; line-height:1.8; color:#94a3b8;">
    <strong style="color:#f8fafc;">Key Takeaways:</strong><br>
    • JavaScript is single-threaded but <em>concurrency bugs still happen</em> when async operations interleave.<br>
    • A <strong style="color:#f87171;">read-modify-write</strong> on shared state without synchronization is a classic race condition.<br>
    • The fix serializes <em>only the critical section</em> (the write) — async work still runs in parallel.<br>
    • In production, use <strong>atomic operations</strong>, <strong>immutable state + reducers</strong>, or a <strong>mutex/semaphore</strong> library.<br>
    • React's <code style="color:#86efac;">setState</code> functional updater (<code style="color:#86efac;">prev => prev + 1</code>) is the idiomatic JS fix for this pattern.
  </div>
</div>

<script>
// ─────────────────────────────────────────────
//  TASK DEFINITIONS
// ─────────────────────────────────────────────
const TASKS = [
  { name: 'Fetch Data',    contribution: 20, delay: 80  },
  { name: 'Parse JSON',    contribution: 15, delay: 50  },
  { name: 'Validate',      contribution: 25, delay: 120 },
  { name: 'Transform',     contribution: 20, delay: 60  },
  { name: 'Save Results',  contribution: 20, delay: 90  },
];

// ─────────────────────────────────────────────
//  UTILITIES
// ─────────────────────────────────────────────
function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

function randomJitter(base) {
  // Add random jitter to make race conditions more likely
  return base + Math.floor(Math.random() * 60);
}

function log(boxId, msg, type = 'info') {
  const box = document.getElementById(boxId);
  const entry = document.createElement('div');
  entry.className = `log-entry ${type}`;
  const ts = new Date().toLocaleTimeString('en', { hour12: false,
    hour: '2-digit', minute: '2-digit', second: '2-digit' });
  entry.textContent = `[${ts}] ${msg}`;
  box.appendChild(entry);
  box.scrollTop = box.scrollHeight;
}

function clearLog(boxId) {
  document.getElementById(boxId).innerHTML = '';
}

function setTaskStatus(containerId, taskName, status, contrib) {
  const card = document.querySelector(`#${containerId} [data-task="${taskName}"]`);
  if (!card) return;
  const statusEl = card.querySelector('.task-status');
  statusEl.className = `task-status status-${status}`;
  const labels = { pending: '⏳ Pending', running: '⚙ Running',
                   done: '✓ Done', conflict: '⚡ Conflict!' };
  statusEl.textContent = labels[status] || status;
  if (contrib !== undefined) {
    card.querySelector('.task-contrib').textContent = `+${contrib}% applied`;
  }
}

function buildTaskCards(containerId, tasks) {
  const container = document.getElementById(containerId);
  container.innerHTML = '';
  tasks.forEach(t => {
    const card = document.createElement('div');
    card.className = 'task-card';
    card.dataset.task = t.name;
    card.innerHTML = `
      <div class="task-name">${t.name}</div>
      <div class="task-status status-pending">⏳ Pending</div>
      <div class="task-contrib">+${t.contribution}% expected</div>`;
    container.appendChild(card);
  });
}

function updateBuggyBar(pct, overflows, lostUpdates, conflicts, expected) {
  const clamped = Math.min(pct, 120); // allow overflow to show visually
  const w = Math.min(clamped, 100);
  const bar = document.getElementById('buggyBar');
  bar.style.width = w + '%';
  bar.textContent = pct > 0 ? pct + '%' : '';

  if (pct > 100) {
    bar.classList.add('overflow');
  } else {
    bar.classList.remove('overflow');
  }

  document.getElementById('buggyPctLabel').textContent   = pct + '%';
  document.getElementById('buggyPctDisplay').textContent = pct + '%';
  document.getElementById('buggyCurrentVal').textContent = pct;
  document.getElementById('buggyExpected').textContent   = expected;
  document.getElementById('buggyOverflows').textContent  = overflows;
  document.getElementById('buggyLostUpdates').textContent = lostUpdates;
  document.getElementById('buggyConflicts').textContent  = conflicts;

  const disp = document.getElementById('buggyPctDisplay');
  disp.className = 'pct-display ' + (pct > 100 ? 'danger' : pct === expected ? 'ok' : 'warn');
}

function updateFixedBar(pct, expected) {
  const bar = document.getElementById('fixedBar');
  bar.style.width = Math.min(pct, 100) + '%';
  bar.textContent = pct > 0 ? pct + '%' : '';

  document.getElementById('fixedPctLabel').textContent   = pct + '%';
  document.getElementById('fixedPctDisplay').textContent = pct + '%';
  document.getElementById('fixedCurrentVal').textContent = pct;
  document.getElementById('fixedExpected').textContent   = expected;
  document.getElementById('fixedOverflows').textContent  = 0;
  document.getElementById('fixedLostUpdates').textContent = 0;
  document.getElementById('fixedConflicts').textContent  = 0;
}

// ─────────────────────────────────────────────
//  BUGGY IMPLEMENTATION
// ─────────────────────────────────────────────
let buggyRunning = false;

async function runBuggy() {
  if (buggyRunning) return;
  buggyRunning = true;
  disableButtons();

  clearLog('buggyLog');
  buildTaskCards('buggyTasks', TASKS);

  // Shared mutable state — the root of the problem
  let sharedProgress = 0;
  let overflowCount  = 0;
  let lostUpdates    = 0;
  let conflictCount  = 0;
  let expectedTotal  = 0;
  let activeReaders  = 0; // track concurrent reads for conflict detection

  TASKS.forEach(t => expectedTotal += t.contribution);
  updateBuggyBar(0, 0, 0, 0, expectedTotal);
  log('buggyLog', `Starting ${TASKS.length} concurrent tasks (expected total: ${expectedTotal}%)`, 'info');

  const taskPromises = TASKS.map(async (task) => {
    setTaskStatus('buggyTasks', task.name, 'running');
    log('buggyLog', `${task.name}: started (will add ${task.contribution}%)`, 'info');

    // Simulate async work
    await sleep(randomJitter(task.delay));

    // ─── BUGGY READ-MODIFY-WRITE (no lock!) ───────────────────
    activeReaders++;

    // READ stale value
    const readValue = sharedProgress;

    // Simulate slight processing delay between read and write
    // This maximizes the chance of a concurrent write happening
    await sleep(Math.random() * 20);

    // MODIFY
    const newValue = readValue + task.contribution;

    // WRITE — may overwrite another task's update!
    const prevShared = sharedProgress;
    sharedProgress = newValue;
    activeReaders--;

    // ── Detect anomalies ──────────────────────────────────────
    if (activeReaders > 0) {
      // Another task read concurrently — conflict!
      conflictCount++;
      setTaskStatus('buggyTasks', task.name, 'conflict', task.contribution);
      log('buggyLog',
        `⚡ CONFLICT: ${task.name} read=${readValue} wrote=${newValue} (${activeReaders} concurrent readers!)`,
        'err');
    } else {
      setTaskStatus('buggyTasks', task.name, 'done', task.contribution);
    }

    // Detect lost updates: if prevShared was already higher, we may have overwritten
    if (prevShared > readValue) {
      const lost = prevShared - readValue;
      lostUpdates += lost;
      log('buggyLog',
        `💀 LOST UPDATE: ${task.name} overwrote ${prevShared}% → ${newValue}% (lost ${lost}%)`,
        'err');
    }

    if (sharedProgress > 100) {
      overflowCount++;
      log('buggyLog', `🔴 OVERFLOW: progress = ${sharedProgress}% (exceeds 100%!)`, 'err');
    } else {
      log('buggyLog', `${task.name}: wrote ${sharedProgress}% (read was ${readValue})`, 'ok');
    }

    updateBuggyBar(sharedProgress, overflowCount, lostUpdates, conflictCount, expectedTotal);
  });

  await Promise.all(taskPromises);

  const finalPct = sharedProgress;
  log('buggyLog', `─── FINAL: ${finalPct}% (expected ${expectedTotal}%) ───`, 'warn');

  if (finalPct !== expectedTotal) {
    log('buggyLog',
      `❌ WRONG RESULT: off by ${Math.abs(finalPct - expectedTotal)}% due to race condition!`,
      'err');
  } else {
    log('buggyLog', `✓ Lucky — got correct result this run (try again!)`, 'ok');
  }

  buggyRunning = false;
  enableButtons();
}

// ─────────────────────────────────────────────
//  FIXED IMPLEMENTATION
// ─────────────────────────────────────────────
let fixedRunning = false;

async function runFixed() {
  if (fixedRunning) return;
  fixedRunning = true;
  disableButtons();

  clearLog('fixedLog');
  buildTaskCards('fixedTasks', TASKS);

  // Shared state
  let sharedProgress = 0;
  let expectedTotal  = 0;

  // ── MUTEX: a promise chain that serializes critical sections ──
  let mutex = Promise.resolve();

  function acquireLock(fn) {
    // Chain the critical section onto the mutex queue.
    // Each critical section waits for the previous to complete.
    const result = mutex.then(fn);
    // Update the mutex chain (ignore errors so chain doesn't break)
    mutex = result.catch(() => {});
    return result;
  }

  TASKS.forEach(t => expectedTotal += t.contribution);
  updateFixedBar(0, expectedTotal);
  log('fixedLog', `Starting ${TASKS.length} concurrent tasks (expected total: ${expectedTotal}%)`, 'info');

  const taskPromises = TASKS.map(async (task) => {
    setTaskStatus('fixedTasks', task.name, 'running');
    log('fixedLog', `${task.name}: started (will add ${task.contribution}%)`, 'info');

    // ── Async work runs fully in parallel ─────────────────────
    await sleep(randomJitter(task.delay));

    // ── Critical section: serialized via mutex ─────────────────
    await acquireLock(async () => {
      const before = sharedProgress;

      // Safe: no other task can enter this section simultaneously
      sharedProgress += task.contribution;

      log('fixedLog',
        `🔒 ${task.name}: ${before}% → ${sharedProgress}% (+${task.contribution}%)`,
        'ok');

      updateFixedBar(sharedProgress, expectedTotal);
      setTaskStatus('fixedTasks', task.name, 'done', task.contribution);
    });
  });

  await Promise.all(taskPromises);

  // Wait for mutex to fully drain
  await mutex;

  const finalPct = sharedProgress;
  log('fixedLog', `─── FINAL: ${finalPct}% (expected ${expectedTotal}%) ───`, 'info');

  if (finalPct === expectedTotal) {
    log('fixedLog', `✅ CORRECT: mutex prevented all race conditions!`, 'ok');
  } else {
    log('fixedLog', `❌ Unexpected error: ${finalPct}%`, 'err');
  }

  fixedRunning = false;
  enableButtons();
}

// ─────────────────────────────────────────────
//  BUTTON MANAGEMENT
// ─────────────────────────────────────────────
function disableButtons() {
  ['btnRunBuggy','btnRunFixed','btnBoth','btnReset'].forEach(id => {
    document.getElementById(id).disabled = true;
  });
}

function enableButtons() {
  if (!buggyRunning && !fixedRunning) {
    ['btnRunBuggy','btnRunFixed','btnBoth','btnReset'].forEach(id => {
      document.getElementById(id).disabled = false;
    });
  }
}

function resetAll() {
  if (buggyRunning || fixedRunning) return;

  // Reset buggy
  updateBuggyBar(0, 0, 0, 0, 0);
  clearLog('buggyLog');
  document.getElementById('buggyTasks').innerHTML = '';

