  const durations = [900, 1400, 1400, 2200]; // same timings as buggy

  TASK_NAMES.forEach((name, i) => {
    const steps = 8;
    const stepTime = durations[i] / steps;

    for (let s = 1; s <= steps; s++) {
      const t = setTimeout(() => {
        const pct = (s / steps) * 100;

        // ══ THE FIX ══
        // Write ONLY to our own slot. No other task touches progressSlots[i].
        progressSlots[i] = pct;
        setBar('fixed', i, pct);

        // Derive overall from the full array — pure read, no write conflict
        const overall = computeOverall();
        setOverall('fixed', overall);

        if (s === steps) {
          completedCount++;
          log('fixed-log',
            `"${name}" done. slots=[${progressSlots.map(v=>Math.round(v)).join(',')}] → overall ${Math.round(overall)}%`,
            completedCount === TASK_COUNT ? 'log-ok' : 'log-info'
          );

          if (completedCount === TASK_COUNT) {
            log('fixed-log', '✅ All tasks complete — bar reached exactly 100%. No jumps, no lost updates.', 'log-ok');
            fixedRunning = false;
            document.getElementById('btn-fixed').disabled = false;
          }
        }
      }, stepTime * s + (i * 2)); // same tiny offset as buggy for fair comparison
      fixedTimers.push(t);
    }
  });
}

function resetFixed() {
  fixedTimers.forEach(clearTimeout);
  fixedTimers = [];
  fixedRunning = false;
  progressSlots = new Array(TASK_COUNT).fill(0);
  buildTaskRows('fixed-tasks', 'fixed');
  setOverall('fixed', 0);
  document.getElementById('fixed-log').innerHTML = 'Reset. Ready to run.';
  document.getElementById('fixed-log')._lines = [];
  document.getElementById('btn-fixed').disabled = false;
}

/* ── init ── */
buildTaskRows('buggy-tasks', 'buggy');
buildTaskRows('fixed-tasks', 'fixed');
</script>
</body>
</html>
```

## What this demo shows you

**The buggy side** deliberately schedules tasks 2 and 3 to finish at the exact same millisecond. Both callbacks execute a **read → (imaginary async gap) → write** sequence against the same `sharedCompletedCount` variable. Both read the stale value, both write `stale + 1`, so the counter ends up one short — the bar skips a step, jumps wrong percentages, and the log prints the collision in red.

**The fixed side** uses the same timing but each task writes only to `progressSlots[i]` — its own isolated array slot. The overall percentage is computed by **reducing the whole array** on every tick, which is a pure read with no shared write target. No matter what order or timing the callbacks fire in, the math is always derived from ground truth.

**The core rule:** never let multiple async actors share a single write target for aggregated state. Instead, give each actor its own isolated state slot and compute aggregates as a pure derivation from all slots. This pattern scales from `setTimeout` all the way up to distributed systems.

