  { id: 'B', label: 'Task B  (medium)', steps: 6,  baseDelay: 200 },
  { id: 'C', label: 'Task C  (slow)',   steps: 5,  baseDelay: 280 },
];

// ─────────────────────────────────────────────
//  BUILD DOM ROWS
// ─────────────────────────────────────────────
function buildRows(containerId, prefix) {
  const container = document.getElementById(containerId);
  container.innerHTML = '';
  TASKS.forEach(t => {
    container.innerHTML += `
      <div class="task-row">
        <label><span>${t.label}</span><span id="${prefix}-pct-${t.id}">0%</span></label>
