buildRows('fixed-tasks', 'fixed');

// ─────────────────────────────────────────────
//  HELPERS
// ─────────────────────────────────────────────
function setBar(id, pct, extraClass = '') {
  const el = document.getElementById(id);
  if (!el) return;
  const clamped = Math.min(Math.max(pct, 0), 100);
  el.style.width = clamped + '%';
  el.className = 'bar-fill' + (extraClass ? ' ' + extraClass : '');
}

function setTotalBar(prefix, pct, extraClass = '') {
  const bar = document.getElementById(`${prefix}-total-bar`);
  const lbl = document.getElementById(`${prefix}-total-pct`);
  const clamped = Math.min(Math.max(pct, 0), 100);
  if (bar) {
    bar.style.width = clamped + '%';
    bar.className   = 'total-fill' + (extraClass ? ' ' + extraClass : '');
  }
  if (lbl) lbl.textContent = Math.round(pct) + '%';
}

function setStatus(prefix, html) {
  const el = document.getElementById(`${prefix}-status`);
  if (el) el.innerHTML = html;
}

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

function jitter(base) { return base + (Math.random() - 0.5) * base * 0.6; }

// ─────────────────────────────────────────────
//  BUGGY VERSION
// ─────────────────────────────────────────────
let buggyRunning = false;

// THE SHARED MUTABLE STATE — the source of all evil
let totalProgress = 0;
let lostUpdates   = 0;
let buggyLog      = [];

async function buggyTask(task) {
  const stepSize = 100 / task.steps;

  for (let i = 1; i <= task.steps; i++) {
    await sleep(jitter(task.baseDelay));

    const pct = (i / task.steps) * 100;

    // Update individual bar (this part is fine)
    setBar(`buggy-bar-${task.id}`, pct);
    document.getElementById(`buggy-pct-${task.id}`).textContent = Math.round(pct) + '%';

    // ── THE BUG ──────────────────────────────────────────
    // Read-modify-write on shared state with an async gap.
    // Another task may have written between our read and write.
    const before = totalProgress;          // READ  (potentially stale)
    await sleep(jitter(15));               // ← async gap — this is where races happen
    const contribution = stepSize / TASKS.length;
    const expected     = before + contribution;
    totalProgress      = expected;         // WRITE (may overwrite another task's update)
    // ─────────────────────────────────────────────────────

    // Detect lost updates by checking if total went backwards or stalled
    // (In a real app you'd never even know this happened)
    const displayPct = Math.min(totalProgress, 100);
    const overshoot  = totalProgress > 100;
    setTotalBar('buggy', displayPct, overshoot ? 'overshoot' : '');

    document.getElementById('buggy-total-pct').textContent =
      Math.round(totalProgress) + '%' + (overshoot ? ' ⚠' : '');
  }
}

async function runBuggy() {
  if (buggyRunning) return;
  buggyRunning = true;
  totalProgress = 0;
  lostUpdates   = 0;
  buggyLog      = [];

  document.getElementById('buggy-run').disabled = true;
  setStatus('buggy', '<span class="warn">⏳ Running… watch the total carefully</span>');

  // Launch all tasks simultaneously — they race each other
  const start = Date.now();
  await Promise.all(TASKS.map(t => buggyTask(t)));

  const elapsed   = ((Date.now() - start) / 1000).toFixed(1);
  const finalPct  = Math.round(totalProgress);
  const expected  = 100;
  const lost      = expected - Math.min(finalPct, expected);

  let msg;
  if (finalPct === 100) {
    // Sometimes it gets lucky — that's the insidious part of race conditions
    msg = `<span class="warn">⚠ Got lucky this time — final: ${finalPct}% in ${elapsed}s.<br>
           Race conditions are non-deterministic. Run again to see failures.</span>`;
  } else if (finalPct > 100) {
    msg = `<span class="err">💥 Overshot! Final: ${finalPct}% (expected 100%) in ${elapsed}s.<br>
           Concurrent writes added the same progress twice.</span>`;
  } else {
    msg = `<span class="err">💀 Lost updates! Final: ${finalPct}% instead of 100% in ${elapsed}s.<br>
           ~${lost}% of progress was silently discarded by stale overwrites.</span>`;
  }

  setStatus('buggy', msg);
  document.getElementById('buggy-run').disabled   = false;
  buggyRunning = false;
}

function resetBuggy() {
  if (buggyRunning) return;
  totalProgress = 0;
  TASKS.forEach(t => {
    setBar(`buggy-bar-${t.id}`, 0);
    document.getElementById(`buggy-pct-${t.id}`).textContent = '0%';
  });
  setTotalBar('buggy', 0);
  setStatus('buggy', 'Press <strong>Run</strong> to start the simulation.');
}

// ─────────────────────────────────────────────
//  FIXED VERSION
// ─────────────────────────────────────────────
let fixedRunning = false;

// Each task owns its own isolated slot — no sharing
const taskProgress = {};

function deriveTotal() {
  // Total is COMPUTED from individual values, never stored separately
  const values = TASKS.map(t => taskProgress[t.id] || 0);
  return values.reduce((sum, v) => sum + v, 0) / TASKS.length;
}

async function fixedTask(task) {
  for (let i = 1; i <= task.steps; i++) {
    await sleep(jitter(task.baseDelay));

    const pct = (i / task.steps) * 100;

    // ── THE FIX ──────────────────────────────────────────
    // Each task writes ONLY to its own isolated key.
    // No other task touches this key — zero contention.
    taskProgress[task.id] = pct;

    // Total is derived fresh every time — no shared counter
    const total = deriveTotal();
    // ─────────────────────────────────────────────────────

    setBar(`fixed-bar-${task.id}`, pct);
    document.getElementById(`fixed-pct-${task.id}`).textContent = Math.round(pct) + '%';
    setTotalBar('fixed', total);
  }
}

async function runFixed() {
  if (fixedRunning) return;
  fixedRunning = true;

  TASKS.forEach(t => { taskProgress[t.id] = 0; });

  document.getElementById('fixed-run').disabled = true;
  setStatus('fixed', '<span class="ok">⏳ Running… total will always be correct</span>');

  const start = Date.now();
  await Promise.all(TASKS.map(t => fixedTask(t)));

  const elapsed  = ((Date.now() - start) / 1000).toFixed(1);
  const finalPct = Math.round(deriveTotal());

  setStatus('fixed',
    `<span class="ok">✅ Perfect! Final: ${finalPct}% in ${elapsed}s.<br>
     Every update counted. No races. No lost progress.</span>`);

  document.getElementById('fixed-run').disabled = false;
  fixedRunning = false;
}

function resetFixed() {
  if (fixedRunning) return;
  TASKS.forEach(t => {
    taskProgress[t.id] = 0;
    setBar(`fixed-bar-${t.id}`, 0);
    document.getElementById(`fixed-pct-${t.id}`).textContent = '0%';
  });
  setTotalBar('fixed', 0);
  setStatus('fixed', 'Press <strong>Run</strong> to start the simulation.');
}
</script>
</body>
