<!-- ===== EXPLANATION ===== -->
<div class="explanation">
  <h3>🔬 What's Actually Happening Here</h3>

  <h4>The Bug: Read-Modify-Write on Shared Mutable State</h4>
  <p>
    JavaScript is single-threaded but <strong>not atomic</strong> across async boundaries.
    When a <code>setTimeout</code> callback fires, it reads the current shared value,
    computes a new value, and writes it back. If two callbacks fire in the same
    event loop tick (or back-to-back before either has written), they both read
    the <em>same stale value</em> and their writes collide — one overwrites the other.
  </p>

  <h4>The Buggy Pattern (what the left side does)</h4>
  <p>Each task does this:</p>
  <p><code>shared.totalProgress = shared.totalProgress + myDelta</code></p>
  <p>
    Task A reads <code>40</code>, Task B reads <code>40</code> (same stale snapshot),
    Task A writes <code>53</code>, Task B writes <code>47</code> — Task A's update is
    <span class="highlight-bad">silently lost</span>. The combined bar never reaches 100%.
    The more tasks, the worse it gets.
  </p>

  <h4>Why the Bar Visually Breaks</h4>
  <p>
    The combined bar is driven by <code>shared.totalProgress</code>.
    Because writes clobber each other, the value oscillates, stalls,
    and almost always <span class="highlight-bad">ends below 100%</span> — sometimes
    dramatically so. Each run produces a different wrong answer (non-deterministic).
  </p>

  <h4>The Fix: Owned Slices + Derived State (what the right side does)</h4>
  <p>
    Each task writes <em>only to its own key</em>: <code>taskState.A</code>,
    <code>taskState.B</code>, <code>taskState.C</code>. The combined total is
    <em>derived</em> by summing all slices — never mutated directly.
    There is no shared write target, so there is nothing to race on.
    <span class="highlight-good">Every update lands. The bar always hits 100%.</span>
  </p>

  <h4>Real-World Equivalents</h4>
  <ul>
    <li>Multiple API responses updating a shared Redux store without reducers</li>
    <li>Concurrent DB transactions without row-level locking or optimistic concurrency</li>
    <li>Node.js streams writing to a shared buffer without a queue/semaphore</li>
    <li>React state updates via <code>setState(this.state.count + 1)</code> instead of <code>setState(prev => prev + 1)</code></li>
    <li>Multiple goroutines writing a shared map without a mutex in Go</li>
  </ul>

  <h4>The Fix Pattern (universally applicable)</h4>
  <p>
    <strong>1. Owned partitions:</strong> Each writer owns a unique key — never share a write target.<br>
    <strong>2. Derive, don't accumulate:</strong> Compute aggregates from owned slices on read, not on write.<br>
    <strong>3. If you must share:</strong> Use a queue, a mutex, or atomic compare-and-swap — never naked read-modify-write.
  </p>
</div>

<script>
// ─────────────────────────────────────────────
// UTILITIES
// ─────────────────────────────────────────────
function setBar(id, pct) {
  const fill = document.getElementById(id);
  const text = document.getElementById(id + '-text');
  const p = Math.max(0, Math.min(100, pct));
  if (fill) fill.style.width = p + '%';
  if (text) text.textContent = Math.round(p) + '%';
}

function setPct(id, pct) {
  const el = document.getElementById(id);
  if (el) el.textContent = Math.round(pct) + '%';
}

function log(panelId, msg, type = 'entry') {
  const logEl = document.getElementById(panelId + '-log');
  if (!logEl) return;
  const line = document.createElement('div');
  line.className = 'entry ' + type;
  const ts = performance.now().toFixed(1);
  line.textContent = `[${ts}ms] ${msg}`;
  logEl.appendChild(line);
  logEl.scrollTop = logEl.scrollHeight;
}

function setRaceIndicator(id, racing) {
  const el = document.getElementById(id + '-race-indicator');
  if (!el) return;
  el.className = 'race-indicator ' + (racing ? 'racing' : 'idle');
  el.textContent = racing ? '⚡ RACE CONDITION ACTIVE' : '● idle';
}

// ─────────────────────────────────────────────
// BUGGY VERSION
// ─────────────────────────────────────────────

// This is the shared mutable state object that all tasks fight over.
// The bug: every task does shared.totalProgress += delta
// which is a non-atomic read-modify-write.
let buggyShared = {
  totalProgress: 0,
  lastWriter: '—',
  writeCount: 0,
  expectedWrites: 0
};

let buggyTaskProgress = { A: 0, B: 0, C: 0 };
let buggyLostUpdates = 0;
let buggyExpectedFinal = 0;
let buggyRunning = false;
let buggyTimers = [];

function resetBuggy() {
  buggyTimers.forEach(t => clearTimeout(t));
  buggyTimers = [];
  buggyRunning = false;
  buggyShared = { totalProgress: 0, lastWriter: '—', writeCount: 0, expectedWrites: 0 };
  buggyTaskProgress = { A: 0, B: 0, C: 0 };
  buggyLostUpdates = 0;
  buggyExpectedFinal = 0;

  ['a','b','c','combined'].forEach(k => { setBar('buggy-bar-' + k, 0); setPct('buggy-' + k + '-pct', 0); });
  document.getElementById('buggy-total').textContent = '0';
  document.getElementById('buggy-total').className = 'val';
  document.getElementById('buggy-lastwriter').textContent = '—';
  document.getElementById('buggy-writecount').textContent = '0';
  document.getElementById('buggy-expected').textContent = '—';
  document.getElementById('buggy-corrupted').textContent = 'no';
  document.getElementById('buggy-corrupted').className = 'val';
  document.getElementById('buggy-lost-updates').textContent = 'Lost updates: 0 | Final expected: — | Final actual: —';
  document.getElementById('buggy-log').innerHTML = '';
  setRaceIndicator('buggy', false);
  document.getElementById('btn-buggy-run').disabled = false;
}

function runBuggy() {
  if (buggyRunning) return;
  buggyRunning = true;
  document.getElementById('btn-buggy-run').disabled = true;
  setRaceIndicator('buggy', true);
  log('buggy', 'Starting 3 concurrent tasks on shared state...', 'info');

  // Each task will do STEPS increments of DELTA_PER_STEP
  // Total contribution per task: STEPS * DELTA_PER_STEP
  // 3 tasks * 10 steps * ~3.33 = ~100 total expected
  const STEPS = 10;
  const DELTAS = { A: 3.5, B: 3.0, C: 3.5 }; // per step, sum = 100 total
  // A: 10*3.5=35, B: 10*3.0=30, C: 10*3.5=35 → total = 100
  buggyExpectedFinal = 100;
  buggyShared.expectedWrites = STEPS * 3;
  document.getElementById('buggy-expected').textContent = STEPS * 3;

  // Track what each task INTENDS to add so we can detect lost updates
  let taskIntendedTotal = { A: 0, B: 0, C: 0 };

  function buggyTaskStep(taskName, stepNum, delta) {
    // ══════════════════════════════════════════════════
    // THE BUG IS HERE:
    // We read shared.totalProgress, add delta, write back.
    // If two tasks fire at the same time, they both read
    // the same stale value. One write clobbers the other.
    // ══════════════════════════════════════════════════
    const valueBefore = buggyShared.totalProgress;  // STALE READ
    const newValue = valueBefore + delta;            // COMPUTE
    // ← another task could fire here in a real thread scenario
    // In JS, we simulate the clobber by scheduling tasks at identical delays
    buggyShared.totalProgress = newValue;            // WRITE (may clobber)
    buggyShared.lastWriter = taskName;
    buggyShared.writeCount++;

    buggyTaskProgress[taskName] = Math.min(100, (buggyTaskProgress[taskName] || 0) + (delta / DELTAS[taskName]) * 10);
    taskIntendedTotal[taskName] = (taskIntendedTotal[taskName] || 0) + delta;

    // Update individual bars accurately (they have their own state - not buggy)
    const taskPct = (stepNum + 1) / STEPS * 100;
    setBar('buggy-bar-' + taskName.toLowerCase(), taskPct);
    setPct('buggy-' + taskName.toLowerCase() + '-pct', taskPct);

    // The COMBINED bar shows the corrupted shared state
    setBar('buggy-bar-combined', buggyShared.totalProgress);
    setPct('buggy-combined-pct', buggyShared.totalProgress);

    // Update state display
    const totalEl = document.getElementById('buggy-total');
    totalEl.textContent = buggyShared.totalProgress.toFixed(2);

    // Calculate what the true total should be at this point
    const trueTotalSoFar = taskIntendedTotal.A + taskIntendedTotal.B + taskIntendedTotal.C;
    const discrepancy = Math.abs(trueTotalSoFar - buggyShared.totalProgress);

    if (discrepancy > 0.5) {
      totalEl.className = 'val bad';
      buggyLostUpdates++;
      log('buggy',
        `LOST UPDATE! Task ${taskName} wrote ${newValue.toFixed(2)} but true total should be ${trueTotalSoFar.toFixed(2)} (lost ${discrepancy.toFixed(2)})`,
        'err');
      document.getElementById('buggy-corrupted').textContent = 'YES — ' + buggyLostUpdates + ' lost writes';
      document.getElementById('buggy-corrupted').className = 'val bad';
    } else {
      log('buggy', `Task ${taskName} step ${stepNum+1}: wrote ${newValue.toFixed(2)} (prev: ${valueBefore.toFixed(2)})`, 'entry');
    }

    document.getElementById('buggy-lastwriter').textContent = taskName;
    document.getElementById('buggy-writecount').textContent = buggyShared.writeCount;
    document.getElementById('buggy-lost-updates').textContent =
      `Lost updates: ${buggyLostUpdates} | Final expected: ${buggyExpectedFinal} | Final actual: ${buggyShared.totalProgress.toFixed(2)}`;

    // Check if all done
    if (buggyShared.writeCount >= buggyShared.expectedWrites) {
      const finalActual = buggyShared.totalProgress;
      const finalExpected = buggyExpectedFinal;
      const totalLost = Math.abs(finalExpected - finalActual);
      setRaceIndicator('buggy', false);
      buggyRunning = false;

      if (totalLost > 1) {
        log('buggy', `DONE. Expected: ${finalExpected}, Got: ${finalActual.toFixed(2)}, LOST: ${totalLost.toFixed(2)}`, 'err');
        document.getElementById('buggy-bar-combined').style.background = '#ff6b6b';
      } else {
        log('buggy', `DONE. Got lucky this run — try again for corruption`, 'warn');
      }
      document.getElementById('buggy-lost-updates').textContent =
        `Lost updates: ${buggyLostUpdates} | Expected: ${finalExpected} | Actual: ${finalActual.toFixed(2)} | Lost: ${totalLost.toFixed(2)}`;
    }
  }

  // ══════════════════════════════════════════════════════════════
  // SCHEDULING STRATEGY TO GUARANTEE COLLISIONS:
  // We schedule multiple tasks at the SAME delay values so they
  // fire in the same event loop drain and read each other's
  // stale pre-write values. This reliably produces lost updates.
  // ══════════════════════════════════════════════════════════════
  for (let step = 0; step < STEPS; step++) {
    // All three tasks fire at the same timestamp for each step
    // This maximally exposes the race — same-tick reads of shared state
    const baseDelay = step * 180;

    // Task A fires at baseDelay
    buggyTimers.push(setTimeout(() => buggyTaskStep('A', step, DELTAS.A), baseDelay));
    // Task B fires at baseDelay + 1ms (nearly simultaneous — reads A's pre-write value)
    buggyTimers.push(setTimeout(() => buggyTaskStep('B', step, DELTAS.B), baseDelay + 1));
    // Task C fires at baseDelay + 2ms (reads B's pre-write value, clobbers A and B)
    buggyTimers.push(setTimeout(() => buggyTaskStep('C', step, DELTAS.C), baseDelay + 2));
  }
}

// ─────────────────────────────────────────────
// FIXED VERSION
// ─────────────────────────────────────────────

// Each task owns its own slice. No task ever writes to another task's key.
// The total is DERIVED by summing slices — never accumulated into a shared variable.
let fixedTaskState = { A: 0, B: 0, C: 0 };
let fixedWriteCount = 0;
let fixedExpectedWrites = 0;
let fixedRunning = false;
let fixedTimers = [];

function getFixedTotal() {
  // Derived, not stored — this is the key insight
  return fixedTaskState.A + fixedTaskState.B + fixedTaskState.C;
}

function resetFixed() {
  fixedTimers.forEach(t => clearTimeout(t));
  fixedTimers = [];
  fixedRunning = false;
  fixedTaskState = { A: 0, B: 0, C: 0 };
  fixedWriteCount = 0;
  fixedExpectedWrites = 0;

  ['a','b','c','combined'].forEach(k => { setBar('fixed-bar-' + k, 0); setPct('fixed-' + k + '-pct', 0); });
  document.getElementById('fixed-a-state').textContent = '0';
  document.getElementById('fixed-b-state').textContent = '0';
  document.getElementById('fixed-c-state').textContent = '0';
  document.getElementById('fixed-total').textContent = '0';
  document.getElementById('fixed-corrupted').textContent = 'no';
  document.getElementById('fixed-corrupted').className = 'val';
  document.getElementById('fixed-lost-updates').textContent = 'Lost updates: 0 | Final expected: — | Final actual: —';
  document.getElementById('fixed-log').innerHTML = '';
  setRaceIndicator('fixed', false);
  document.getElementById('btn-fixed-run').disabled = false;
}

function runFixed() {
  if (fixedRunning) return;
  fixedRunning = true;
  document.getElementById('btn-fixed-run').disabled = true;
  setRaceIndicator('fixed', true);
  log('fixed', 'Starting 3 concurrent tasks with owned state slices...', 'info');

  const STEPS = 10;
  const DELTAS = { A: 3.5, B: 3.0, C: 3.5 };
  fixedExpectedWrites = STEPS * 3;

  function fixedTaskStep(taskName, stepNum, delta) {
    // ══════════════════════════════════════════════════
    // THE FIX:
    // Each task ONLY writes to its own key.
    // fixedTaskState[taskName] is exclusively owned by taskName.
    // No other task writes here. Zero contention.
    // The total is computed fresh from all slices on every read.
    // ══════════════════════════════════════════════════
    fixedTaskState[taskName] += delta;  // SAFE: exclusive ownership
    fixedWriteCount++;

    const taskPct = (stepNum + 1) / STEPS * 100;
    setBar('fixed-bar-' + taskName.toLowerCase(), taskPct);
    setPct('fixed-' + taskName.toLowerCase() + '-pct', taskPct);

    // Derive total — never read-modify-write a shared accumulator
    const derivedTotal = getFixedTotal();

    setBar('fixed-bar-combined', derivedTotal);
    setPct('fixed-combined-pct', derivedTotal);

    document.getElementById('fixed-a-state').textContent = fixedTaskState.A.toFixed(2);
    document.getElementById('fixed-b-state').textContent = fixedTaskState.B.toFixed(2);
    document.getElementById('fixed-c-state').textContent = fixedTaskState.C.toFixed(2);
    document.getElementById('fixed-total').textContent = derivedTotal.toFixed(2);

    log('fixed', `Task ${taskName} step ${stepNum+1}: own slice → ${fixedTaskState[taskName].toFixed(2)}, total → ${derivedTotal.toFixed(2)}`, 'ok');

    document.getElementById('fixed-lost-updates').textContent =
      `Lost updates: 0 | Final expected: 100 | Final actual: ${derivedTotal.toFixed(2)}`;

    if (fixedWriteCount >= fixedExpectedWrites) {
      const finalTotal = getFixedTotal();
      setRaceIndicator('fixed', false);
      fixedRunning = false;
      document.getElementById('fixed-corrupted').textContent = 'no — 0 lost writes';
      document.getElementById('fixed-corrupted').className = 'val good';
      log('fixed', `DONE. Expected: 100, Got: ${finalTotal.toFixed(2)} — PERFECT`, 'ok');
      document.getElementById('fixed-lost-updates').textContent =
        `Lost updates: 0 | Expected: 100 | Actual: ${finalTotal.toFixed(2)} | Lost: 0`;
    }
  }

  // Same scheduling as the buggy version — identical timing pressure
  for (let step = 0; step < STEPS; step++) {
    const baseDelay = step * 180;
    fixedTimers.push(setTimeout(() => fixedTaskStep('A', step, DELTAS.A), baseDelay));
    fixedTimers.push(setTimeout(() => fixedTaskStep('B', step, DELTAS.B), baseDelay + 1));
    fixedTimers.push(setTimeout(() => fixedTaskStep('C', step, DELTAS.C), baseDelay + 2));
  }
}
</script>
</body>
</html>
